SELECT DISTINCT p.id, p.name, p.customer_type, p.business_type, p.document_category, p.status, p.owner_id, p.nas_base_path, p.nas_dir_status, p.remark, p.create_by, p.create_time, p.update_time FROM doc_project p
INNER JOIN doc_project_member m ON p.id = m.project_id AND m.user_id = #{userId}
